{"filter":false,"title":"2_根拠付与.py","tooltip":"/pages/2_根拠付与.py","undoManager":{"mark":0,"position":0,"stack":[[{"start":{"row":0,"column":0},"end":{"row":377,"column":8},"action":"remove","lines":["# app_evidence_attach.py — 第2モジュール（根拠付与：インタビュー深掘り）UI","","from __future__ import annotations","import streamlit as st","from datetime import datetime","import re","import copy","","from chains import run_evidence_attach, run_evidence_finalize","from storage import load_ir_history_for_session, save_ir_jsonl","from admin_rag import get_admin_hints  # 管理者RAG","","# ※マルチページ構成なら pages/ 配下では set_page_config しない","# st.set_page_config(page_title=\"根拠付与（インタビュー深掘り）\", layout=\"centered\")","","st.title(\"根拠付与モジュール（インタビュー深掘り）\")","","","# -------------------------------------","# 改行整形関数（UI見た目だけ整える）","# -------------------------------------","def format_for_chat(text: str) -> str:","    \"\"\"見やすいように中点と改行を軽く整形\"\"\"","    text = re.sub(r'^\\s*・', '\\n\\n・', text, flags=re.MULTILINE)","    text = re.sub(r'\\n{3,}', '\\n\\n', text)","    return text.strip()","","# -------------------------------------","# 確定入力判定（@@ / ＠＠）","# -------------------------------------","CONFIRM_PAT = re.compile(r\"^(@@|＠＠)[！!。\\.]?$\", re.IGNORECASE)","","def is_pure_confirmation(text: str) -> bool:","    t = text.strip().replace(\"　\", \"\")","    t = t.replace(\"＠\", \"@\")","    return CONFIRM_PAT.fullmatch(t) is not None","","def next_revision_for_session(session_id: str) -> int:","    items = load_ir_history_for_session(session_id, limit=50)","    revs = []","    for row in items:","        ir = row.get(\"ir\")","        if isinstance(ir, dict):","            r = ir.get(\"revision\")","            if isinstance(r, int):","                revs.append(r)","    return (max(revs) + 1) if revs else 1","","# -------------------------------","# セッション状態の初期化","# -------------------------------","if \"evi_messages\" not in st.session_state:","    # [{\"role\": \"assistant\" | \"user\", \"content\": str, \"ts\": str}, ...]","    st.session_state[\"evi_messages\"] = []","","if \"evi_selected_sid\" not in st.session_state:","    st.session_state[\"evi_selected_sid\"] = \"\"","","if \"evi_selected_ir\" not in st.session_state:","    # 第1モジュールで作成された IR（objective_card を含む dict）","    st.session_state[\"evi_selected_ir\"] = None","","","# =========================================================","# ★ここが追加箇所：URLの ?sid= を受け取って自動でIRを読み込む","# =========================================================","sid_from_url = st.query_params.get(\"sid\")  # 例: ?sid=xxxxx","","# 既に手動で選択済みなら上書きしない（初回だけ自動反映）","if sid_from_url and not st.session_state.get(\"evi_selected_sid\"):","    st.session_state[\"evi_selected_sid\"] = sid_from_url","","# まだIRが読み込まれていない場合だけ、自動ロードする","if sid_from_url and st.session_state.get(\"evi_selected_ir\") is None:","    try:","        items = load_ir_history_for_session(sid_from_url, limit=50)","","        # まず extraction の最新版を優先して拾う","        candidate = None","        for row in items:","            ir = row.get(\"ir\")","            if isinstance(ir, dict) and ir.get(\"stage\") == \"extraction\":","                candidate = ir","                break","","        # extractionが無ければ、とにかくdictなら拾う","        if candidate is None:","            for row in items:","                ir = row.get(\"ir\")","                if isinstance(ir, dict):","                    candidate = ir","                    break","","        if candidate is not None:","            st.session_state[\"evi_selected_sid\"] = sid_from_url","            st.session_state[\"evi_selected_ir\"] = candidate","","            # 遷移直後は新規開始のほうが自然なのでクリア推奨","            st.session_state[\"evi_messages\"] = []","","            st.toast(\"Session ID を受け取り、IRを自動ロードしました。\", icon=\"✅\")","        else:","            st.warning(\"指定されたSession IDのIRが見つかりませんでした。\")","","    except Exception as e:","        st.error(f\"URLのsidからの自動ロードに失敗しました: {e}\")","","# ここから下に「サイドバー（SID入力＋読み込みボタン）」や本体UIが続く想定","","","","# -------------------------------","# サイドバー：IR選択＋RAG設定","# -------------------------------","with st.sidebar:","    st.subheader(\"対象となる Session ID を指定\")","","    # 入力欄：セッション状態を初期値として表示","    sid_input = st.text_input(","        \"第1モジュールで保存された Session ID\",","        value=st.session_state.get(\"evi_selected_sid\", \"\"),","        placeholder=\"例: 123e4567-e89b-12d3-a456-426614174000\",","    )","","    # ★ポイント：入力欄を編集したら即セッションに反映（ロードはボタンで）","    # これにより、コピー貼り付け → すぐボタン押下が自然になる","    if sid_input != st.session_state.get(\"evi_selected_sid\", \"\"):","        st.session_state[\"evi_selected_sid\"] = sid_input","","    col1, col2 = st.columns([1, 1])","    with col1:","        load_btn = st.button(\"IR を読み込む\", use_container_width=True)","    with col2:","        clear_btn = st.button(\"クリア\", use_container_width=True)","","    if clear_btn:","        st.session_state[\"evi_selected_sid\"] = \"\"","        st.session_state[\"evi_selected_ir\"] = None","        st.session_state[\"evi_messages\"] = []","","        # ★URLパラメータも消す（遷移で付いた sid が残ると再ロードされがち）","        try:","            st.query_params.clear()","        except Exception:","            pass","","        st.success(\"クリアしました。\")","","    if load_btn and sid_input:","        try:","            items = load_ir_history_for_session(sid_input, limit=50)","        except Exception as e:","            st.error(f\"IRの読み込みでエラーが発生しました: {e}\")","            items = []","","        # stage == \"extraction\" の最新 IR を優先して採用","        candidate = None","        for row in items:","            ir = row.get(\"ir\")","            if not isinstance(ir, dict):","                continue","            if ir.get(\"stage\") == \"extraction\":","                candidate = ir","                break","","        # 見つからなければ、とりあえず最初の dict IR を採用","        if candidate is None:","            for row in items:","                ir = row.get(\"ir\")","                if isinstance(ir, dict):","                    candidate = ir","                    break","","        if candidate is None:","            st.warning(\"指定した Session ID に対応する IR が見つかりませんでした。\")","        else:","            st.session_state[\"evi_selected_sid\"] = sid_input","            st.session_state[\"evi_selected_ir\"] = candidate","            st.session_state[\"evi_messages\"] = []","            st.success(\"IR を読み込みました。\")","","            # ★読み込み成功時はURLにも反映しておく（再読み込み/共有に便利）","            try:","                st.query_params[\"sid\"] = sid_input","            except Exception:","                pass","","    st.markdown(\"---\")","    st.subheader(\"管理者RAGの利用\")","","    st.checkbox(","        \"インタビュー活用資料 / アイデア・メーカー要約などを内部ヒントとして使う\",","        key=\"evi_use_admin_rag\",","        value=True,","        help=(","            \"管理者RAGからインタビュー観点や質問パターンのヒントだけを取得します。\"","            \"ユーザーには資料名やページ番号などは見せません。\"","        ),","    )","","","# -------------------------------","# 選択中 IR の文脈表示","# -------------------------------","selected_ir = st.session_state.get(\"evi_selected_ir\")","","if selected_ir is None:","    st.info(\"左のサイドバーで Session ID を指定し、第1モジュールの IR を読み込んでください。\")","else:","    oc = (selected_ir.get(\"objective_card\") or {}) if isinstance(selected_ir, dict) else {}","","    st.markdown(\"### 第1モジュールで整理された内容（文脈）\")","","    st.markdown(f\"- **対象ユーザー**：{oc.get('target_user', '')}\")","    st.markdown(f\"- **課題**：{oc.get('problem', '')}\")","    st.markdown(f\"- **矛盾**：{oc.get('contradiction', '')}\")","    st.markdown(f\"- **目的**：{oc.get('objective', '')}\")","    st.markdown(f\"- **価値**：{oc.get('value', '')}\")","    st.markdown(f\"- **背景**：{oc.get('background', '')}\")","","    extras = oc.get(\"extras\") or []","    if extras:","        st.markdown(\"**補足情報（extras）**：\")","        for ex in extras:","            st.markdown(f\"- {ex}\")","","    st.markdown(\"---\")","    st.markdown(","        \"ここからは、上記の内容を前提に **インタビュー** を進めていきます。\\n\\n\"","        \"質問への答えを書いてください。\"","    )","","","# -------------------------------","# これまでのインタビュー対話ログ表示","# -------------------------------","for m in st.session_state[\"evi_messages\"]:","    with st.chat_message(m[\"role\"]):","        st.markdown(m[\"content\"])","        st.caption(m[\"ts\"])","","","# -------------------------------","# ユーザー入力（ペルソナとしての回答）","# -------------------------------","if selected_ir is not None:","    user_text = st.chat_input(\"質問に対する回答を書いてください\")","","    if user_text:","        ts = datetime.utcnow().isoformat() + \"Z\"","","        # 1) ユーザー（=ペルソナ）の回答を表示・保存","        with st.chat_message(\"user\"):","            st.markdown(user_text)","        st.session_state[\"evi_messages\"].append(","            {\"role\": \"user\", \"content\": user_text, \"ts\": ts}","        )","","        # 2) LLM に渡す文脈を組み立てる","        oc = (selected_ir.get(\"objective_card\") or {}) if isinstance(selected_ir, dict) else {}","","        # これまでの対話ログをシンプルなテキストに","        history_lines = []","        for m in st.session_state[\"evi_messages\"]:","            role_jp = \"インタビュアー\" if m[\"role\"] == \"assistant\" else \"ユーザー\"","            history_lines.append(f\"{role_jp}：{m['content']}\")","        history_text = \"\\n\".join(history_lines)","","        composed_input = (","            \"【第1モジュールで整理された内容】\\n\"","            f\"- 対象ユーザー：{oc.get('target_user', '')}\\n\"","            f\"- 課題：{oc.get('problem', '')}\\n\"","            f\"- 矛盾：{oc.get('contradiction', '')}\\n\"","            f\"- 目的：{oc.get('objective', '')}\\n\"","            f\"- 価値：{oc.get('value', '')}\\n\"","            f\"- 背景：{oc.get('background', '')}\\n\\n\"","            \"【これまでのインタビュー対話ログ】\\n\"","            f\"{history_text}\\n\\n\"","            \"【指示】\\n\"","            \"上記の文脈と最新のユーザー回答を踏まえて、\"","            \"次に投げかけるべき「1つの質問文」だけを日本語で生成してください。\\n\"","            \"質問は、状況や理由・感情・対処・理想像などを丁寧に深掘りするものとし、\"","            \"誘導的・評価的な聞き方は避けてください。\\n\"","            \"もし十分に根拠が集まり、explanation 追記済みIRを確定保存する段階だと判断した場合は、\"","            \"質問文の代わりに @@ のみを出力してください。\"","        )","","        # 3) 管理者RAGからのヒントを内部的に追加（必要な場合のみ）","        if st.session_state.get(\"evi_use_admin_rag\", False):","            try:","                admin_hints = get_admin_hints(composed_input)","            except Exception:","                admin_hints = \"\"","","            if admin_hints:","                composed_input += (","                    \"\\n\\n【内部向けヒント（管理者RAG）】\\n\"","                    \"以下は『インタビュー活用資料』や『アイデア・メーカー』などから抽出された、\"","                    \"質問観点や質問テンプレートのヒントです。ユーザーへの表示には使わず、\"","                    \"あなたが質問を考える際の参考としてのみ用いてください。\\n\"","                    f\"{admin_hints}\"","                )","","        # 4) 根拠付与モジュール（次の質問を生成）","        with st.chat_message(\"assistant\"):","            with st.spinner(\"次の質問を考えています...\"):","                try:","                    result = run_evidence_attach(composed_input)","                except Exception as e:","                    st.error(f\"根拠付与モジュールの呼び出しでエラーが発生しました: {e}\")","                    st.session_state[\"evi_messages\"].append(","                        {\"role\": \"assistant\", \"content\": f\"エラーが発生しました: {e}\", \"ts\": ts}","                    )","                    st.stop()","","                q_text = (result.get(\"text\") or \"\").strip()","                if not q_text:","                    q_text = \"すみません、うまく質問を生成できませんでした。もう一度お答えを教えていただけますか？\"","","                normalized = q_text.strip().replace(\"　\", \"\").replace(\"＠\", \"@\")","                if normalized == \"@@\":","                    with st.spinner(\"IR（explanation追記）を確定しています...\"):","                        finalize_input = (","                            \"【第1モジュールIR（objective_card を含む）】\\n\"","                            f\"{selected_ir}\\n\\n\"","                            \"【根拠付与インタビューの全ログ】\\n\"","                            f\"{history_text}\\n\\n\"","                            \"【指示】\\n\"","                            \"上のログを根拠として，objective_card の各項目に対応する explanation を追記し，\"","                            \"更新後の IR(JSON) を1つだけ出力してください．\\n\"","                            \"- 出力は JSON のみ（前後説明禁止）\\n\"","                            \"- target_user/problem/contradiction/objective/value の各 *_explanation は配列で，\"","                            \"  今回追加する要約（根拠）を必要な分だけ append してください．\\n\"","                            \"- background は必要なら更新してよい\\n\"","                            \"- extras は必要なら追加してよい\\n\"","                        )","","                        fin = run_evidence_finalize(finalize_input)","","                        if fin.get(\"mode\") != \"IR\" or not isinstance(fin.get(\"ir\"), dict):","                            st.error(\"IR(JSON)の確定生成に失敗しました。もう一度実行してください。\")","                            st.stop()","","                        new_ir = fin[\"ir\"]","","                        # session_id は「選択中のIRのsession_id」を優先して維持","                        sid = selected_ir.get(\"session_id\") if isinstance(selected_ir, dict) else None","                        if not sid:","                            sid = new_ir.get(\"session_id\")","                        new_ir[\"session_id\"] = sid","","                        # stage を evidence に更新（新規保存するIRなので）","                        new_ir[\"stage\"] = \"evidence\"","","                        # revision を新規に振る","                        new_ir[\"revision\"] = next_revision_for_session(sid)","","                        # 保存（IRの新規保存だけ）","                        save_ir_jsonl(new_ir)","","                        st.markdown(\"IR（explanation 追記済み）を新規保存しました。\")","                        with st.expander(\"保存したIR（開発者向け）\"):","                            st.json(new_ir)","","                        # チャット履歴にも残す（画面の流れのため）","                        st.session_state[\"evi_messages\"].append(","                            {\"role\": \"assistant\", \"content\": \"IR（explanation追記済み）を新規保存しました。\", \"ts\": ts}","                        )","","                        st.stop()","","                # 通常：質問を表示・保存","                st.markdown(q_text)","                st.session_state[\"evi_messages\"].append(","                    {\"role\": \"assistant\", \"content\": q_text, \"ts\": ts}","                )","else:","    pass"],"id":3},{"start":{"row":0,"column":0},"end":{"row":410,"column":0},"action":"insert","lines":["# app_evidence_attach.py — 第2モジュール（根拠付与：インタビュー深掘り）UI","","from __future__ import annotations","import streamlit as st","from datetime import datetime","import re","import copy","import json  # ★追加：JSON整形用","","from chains import run_evidence_attach, run_evidence_finalize","from storage import load_ir_history_for_session, save_ir_jsonl","from admin_rag import get_admin_hints  # 管理者RAG","","# ★追加：根拠付与専用エクスポート（ZIP：ir.json + report.md + meta.json）","from export_bundle_explanation import build_zip_explanation","","# ※マルチページ構成なら pages/ 配下では set_page_config しない","# st.set_page_config(page_title=\"根拠付与（インタビュー深掘り）\", layout=\"centered\")","","st.title(\"根拠付与モジュール（インタビュー深掘り）\")","","","# -------------------------------------","# 改行整形関数（UI見た目だけ整える）","# -------------------------------------","def format_for_chat(text: str) -> str:","    \"\"\"見やすいように中点と改行を軽く整形\"\"\"","    text = re.sub(r'^\\s*・', '\\n\\n・', text, flags=re.MULTILINE)","    text = re.sub(r'\\n{3,}', '\\n\\n', text)","    return text.strip()","","","# -------------------------------------","# 確定入力判定（@@ / ＠＠）","# -------------------------------------","CONFIRM_PAT = re.compile(r\"^(@@|＠＠)[！!。\\.]?$\", re.IGNORECASE)","","def is_pure_confirmation(text: str) -> bool:","    t = text.strip().replace(\"　\", \"\")","    t = t.replace(\"＠\", \"@\")","    return CONFIRM_PAT.fullmatch(t) is not None","","","def next_revision_for_session(session_id: str) -> int:","    items = load_ir_history_for_session(session_id, limit=50)","    revs = []","    for row in items:","        ir = row.get(\"ir\")","        if isinstance(ir, dict):","            r = ir.get(\"revision\")","            if isinstance(r, int):","                revs.append(r)","    return (max(revs) + 1) if revs else 1","","","def json_dumps_safe(obj: object) -> str:","    try:","        return json.dumps(obj, ensure_ascii=False, indent=2)","    except Exception:","        return str(obj)","","","# -------------------------------","# セッション状態の初期化","# -------------------------------","if \"evi_messages\" not in st.session_state:","    # [{\"role\": \"assistant\" | \"user\", \"content\": str, \"ts\": str}, ...]","    st.session_state[\"evi_messages\"] = []","","if \"evi_selected_sid\" not in st.session_state:","    st.session_state[\"evi_selected_sid\"] = \"\"","","if \"evi_selected_ir\" not in st.session_state:","    # 第1モジュールで作成された IR（objective_card を含む dict）","    st.session_state[\"evi_selected_ir\"] = None","","","# =========================================================","# ★ここが追加箇所：URLの ?sid= を受け取って自動でIRを読み込む","# =========================================================","sid_from_url = st.query_params.get(\"sid\")  # 例: ?sid=xxxxx","","# 既に手動で選択済みなら上書きしない（初回だけ自動反映）","if sid_from_url and not st.session_state.get(\"evi_selected_sid\"):","    st.session_state[\"evi_selected_sid\"] = sid_from_url","","# まだIRが読み込まれていない場合だけ、自動ロードする","if sid_from_url and st.session_state.get(\"evi_selected_ir\") is None:","    try:","        items = load_ir_history_for_session(sid_from_url, limit=50)","","        # まず extraction の最新版を優先して拾う","        candidate = None","        for row in items:","            ir = row.get(\"ir\")","            if isinstance(ir, dict) and ir.get(\"stage\") == \"extraction\":","                candidate = ir","                break","","        # extractionが無ければ、とにかくdictなら拾う","        if candidate is None:","            for row in items:","                ir = row.get(\"ir\")","                if isinstance(ir, dict):","                    candidate = ir","                    break","","        if candidate is not None:","            st.session_state[\"evi_selected_sid\"] = sid_from_url","            st.session_state[\"evi_selected_ir\"] = candidate","","            # 遷移直後は新規開始のほうが自然なのでクリア推奨","            st.session_state[\"evi_messages\"] = []","","            st.toast(\"Session ID を受け取り、IRを自動ロードしました。\", icon=\"✅\")","        else:","            st.warning(\"指定されたSession IDのIRが見つかりませんでした。\")","","    except Exception as e:","        st.error(f\"URLのsidからの自動ロードに失敗しました: {e}\")","","# ここから下に「サイドバー（SID入力＋読み込みボタン）」や本体UIが続く想定","","","","# -------------------------------","# サイドバー：IR選択＋RAG設定","# -------------------------------","with st.sidebar:","    st.subheader(\"対象となる Session ID を指定\")","","    # 入力欄：セッション状態を初期値として表示","    sid_input = st.text_input(","        \"第1モジュールで保存された Session ID\",","        value=st.session_state.get(\"evi_selected_sid\", \"\"),","        placeholder=\"例: 123e4567-e89b-12d3-a456-426614174000\",","    )","","    # 入力欄を編集したら即セッションに反映（ロードはボタンで）","    if sid_input != st.session_state.get(\"evi_selected_sid\", \"\"):","        st.session_state[\"evi_selected_sid\"] = sid_input","","    col1, col2 = st.columns([1, 1])","    with col1:","        load_btn = st.button(\"IR を読み込む\", use_container_width=True)","    with col2:","        clear_btn = st.button(\"クリア\", use_container_width=True)","","    if clear_btn:","        st.session_state[\"evi_selected_sid\"] = \"\"","        st.session_state[\"evi_selected_ir\"] = None","        st.session_state[\"evi_messages\"] = []","","        # URLパラメータも消す","        try:","            st.query_params.clear()","        except Exception:","            pass","","        st.success(\"クリアしました。\")","","    if load_btn and sid_input:","        try:","            items = load_ir_history_for_session(sid_input, limit=50)","        except Exception as e:","            st.error(f\"IRの読み込みでエラーが発生しました: {e}\")","            items = []","","        # stage == \"extraction\" の最新 IR を優先して採用","        candidate = None","        for row in items:","            ir = row.get(\"ir\")","            if not isinstance(ir, dict):","                continue","            if ir.get(\"stage\") == \"extraction\":","                candidate = ir","                break","","        # 見つからなければ、とりあえず最初の dict IR を採用","        if candidate is None:","            for row in items:","                ir = row.get(\"ir\")","                if isinstance(ir, dict):","                    candidate = ir","                    break","","        if candidate is None:","            st.warning(\"指定した Session ID に対応する IR が見つかりませんでした。\")","        else:","            st.session_state[\"evi_selected_sid\"] = sid_input","            st.session_state[\"evi_selected_ir\"] = candidate","            st.session_state[\"evi_messages\"] = []","            st.success(\"IR を読み込みました。\")","","            # 読み込み成功時はURLにも反映（再読み込み/共有に便利）","            try:","                st.query_params[\"sid\"] = sid_input","            except Exception:","                pass","","    st.markdown(\"---\")","    st.subheader(\"管理者RAGの利用\")","","    st.checkbox(","        \"インタビュー活用資料 / アイデア・メーカー要約などを内部ヒントとして使う\",","        key=\"evi_use_admin_rag\",","        value=True,","        help=(","            \"管理者RAGからインタビュー観点や質問パターンのヒントだけを取得します。\"","            \"ユーザーには資料名やページ番号などは見せません。\"","        ),","    )","","","# -------------------------------","# 選択中 IR の文脈表示","# -------------------------------","selected_ir = st.session_state.get(\"evi_selected_ir\")","","if selected_ir is None:","    st.info(\"左のサイドバーで Session ID を指定し、第1モジュールの IR を読み込んでください。\")","else:","    oc = (selected_ir.get(\"objective_card\") or {}) if isinstance(selected_ir, dict) else {}","","    st.markdown(\"### 第1モジュールで整理された内容（文脈）\")","","    st.markdown(f\"- **対象ユーザー**：{oc.get('target_user', '')}\")","    st.markdown(f\"- **課題**：{oc.get('problem', '')}\")","    st.markdown(f\"- **矛盾**：{oc.get('contradiction', '')}\")","    st.markdown(f\"- **目的**：{oc.get('objective', '')}\")","    st.markdown(f\"- **価値**：{oc.get('value', '')}\")","    st.markdown(f\"- **背景**：{oc.get('background', '')}\")","","    extras = oc.get(\"extras\") or []","    if extras:","        st.markdown(\"**補足情報（extras）**：\")","        for ex in extras:","            st.markdown(f\"- {ex}\")","","    st.markdown(\"---\")","    st.markdown(","        \"ここからは、上記の内容を前提に **インタビュー** を進めていきます。\\n\\n\"","        \"質問への答えを書いてください。\"","    )","","","# -------------------------------","# これまでのインタビュー対話ログ表示","# -------------------------------","for m in st.session_state[\"evi_messages\"]:","    with st.chat_message(m[\"role\"]):","        st.markdown(m[\"content\"])","        st.caption(m[\"ts\"])","","","# -------------------------------","# ユーザー入力（ペルソナとしての回答）","# -------------------------------","if selected_ir is not None:","    user_text = st.chat_input(\"質問に対する回答を書いてください\")","","    if user_text:","        ts = datetime.utcnow().isoformat() + \"Z\"","","        # 1) ユーザー（=ペルソナ）の回答を表示・保存","        with st.chat_message(\"user\"):","            st.markdown(user_text)","        st.session_state[\"evi_messages\"].append(","            {\"role\": \"user\", \"content\": user_text, \"ts\": ts}","        )","","        # 2) LLM に渡す文脈を組み立てる","        oc = (selected_ir.get(\"objective_card\") or {}) if isinstance(selected_ir, dict) else {}","","        # これまでの対話ログをシンプルなテキストに","        history_lines = []","        for m in st.session_state[\"evi_messages\"]:","            role_jp = \"インタビュアー\" if m[\"role\"] == \"assistant\" else \"ユーザー\"","            history_lines.append(f\"{role_jp}：{m['content']}\")","        history_text = \"\\n\".join(history_lines)","","        composed_input = (","            \"【第1モジュールで整理された内容】\\n\"","            f\"- 対象ユーザー：{oc.get('target_user', '')}\\n\"","            f\"- 課題：{oc.get('problem', '')}\\n\"","            f\"- 矛盾：{oc.get('contradiction', '')}\\n\"","            f\"- 目的：{oc.get('objective', '')}\\n\"","            f\"- 価値：{oc.get('value', '')}\\n\"","            f\"- 背景：{oc.get('background', '')}\\n\\n\"","            \"【これまでのインタビュー対話ログ】\\n\"","            f\"{history_text}\\n\\n\"","            \"【指示】\\n\"","            \"上記の文脈と最新のユーザー回答を踏まえて、\"","            \"次に投げかけるべき「1つの質問文」だけを日本語で生成してください。\\n\"","            \"質問は、状況や理由・感情・対処・理想像などを丁寧に深掘りするものとし、\"","            \"誘導的・評価的な聞き方は避けてください。\\n\"","            \"もし十分に根拠が集まり、explanation 追記済みIRを確定保存する段階だと判断した場合は、\"","            \"質問文の代わりに @@ のみを出力してください。\"","        )","","        # 3) 管理者RAGからのヒントを内部的に追加（必要な場合のみ）","        if st.session_state.get(\"evi_use_admin_rag\", False):","            try:","                admin_hints = get_admin_hints(composed_input)","            except Exception:","                admin_hints = \"\"","","            if admin_hints:","                composed_input += (","                    \"\\n\\n【内部向けヒント（管理者RAG）】\\n\"","                    \"以下は『インタビュー活用資料』や『アイデア・メーカー』などから抽出された、\"","                    \"質問観点や質問テンプレートのヒントです。ユーザーへの表示には使わず、\"","                    \"あなたが質問を考える際の参考としてのみ用いてください。\\n\"","                    f\"{admin_hints}\"","                )","","        # 4) 根拠付与モジュール（次の質問を生成）","        with st.chat_message(\"assistant\"):","            with st.spinner(\"次の質問を考えています...\"):","                try:","                    result = run_evidence_attach(composed_input)","                except Exception as e:","                    st.error(f\"根拠付与モジュールの呼び出しでエラーが発生しました: {e}\")","                    st.session_state[\"evi_messages\"].append(","                        {\"role\": \"assistant\", \"content\": f\"エラーが発生しました: {e}\", \"ts\": ts}","                    )","                    st.stop()","","                q_text = (result.get(\"text\") or \"\").strip()","                if not q_text:","                    q_text = \"すみません、うまく質問を生成できませんでした。もう一度お答えを教えていただけますか？\"","","                # ★修正：@@ 判定は専用関数で（@@! や ＠＠ も吸収）","                if is_pure_confirmation(q_text):","                    with st.spinner(\"IR（explanation追記）を確定しています...\"):","","                        finalize_input = (","                            \"【第1モジュールIR（objective_card を含む）】\\n\"","                            f\"{json_dumps_safe(selected_ir)}\\n\\n\"","                            \"【根拠付与インタビューの全ログ】\\n\"","                            f\"{history_text}\\n\\n\"","                            \"【指示】\\n\"","                            \"上のログを根拠として，objective_card の各項目に対応する explanation を追記し，\"","                            \"更新後の IR(JSON) を1つだけ出力してください．\\n\"","                            \"- 出力は JSON のみ（前後説明禁止）\\n\"","                            \"- target_user/problem/contradiction/objective/value の各 *_explanation は配列で，\"","                            \"  今回追加する要約（根拠）を必要な分だけ append してください．\\n\"","                            \"- background は必要なら更新してよい\\n\"","                            \"- extras は必要なら追加してよい\\n\"","                        )","","                        fin = run_evidence_finalize(finalize_input)","","                        if fin.get(\"mode\") != \"IR\" or not isinstance(fin.get(\"ir\"), dict):","                            st.error(\"IR(JSON)の確定生成に失敗しました。もう一度実行してください。\")","                            st.stop()","","                        new_ir = fin[\"ir\"]","","                        # session_id は「選択中のIRのsession_id」を優先して維持","                        sid = selected_ir.get(\"session_id\") if isinstance(selected_ir, dict) else None","                        if not sid:","                            sid = new_ir.get(\"session_id\")","                        new_ir[\"session_id\"] = sid","","                        # stage を evidence に更新（新規保存するIRなので）","                        new_ir[\"stage\"] = \"evidence\"","","                        # revision を新規に振る","                        new_ir[\"revision\"] = next_revision_for_session(sid)","","                        # 5) 保存（従来どおり）","                        save_ir_jsonl(new_ir)","","                        st.markdown(\"IR（explanation 追記済み）を新規保存しました。\")","","                        # 6) ★追加：ローカル保存ZIP（ir.json + report.md、対話ログなし）","                        zip_bytes, zip_name = build_zip_explanation(","                            new_ir=new_ir,","                            session_id=str(new_ir.get(\"session_id\", \"\")),","                            revision=int(new_ir.get(\"revision\", 0)) if isinstance(new_ir.get(\"revision\", 0), int) else 0,","                            stage=str(new_ir.get(\"stage\", \"evidence\")),","                            extra_meta={\"module\": \"evidence\", \"export\": \"ir.json + report.md\"},","                        )","","                        st.download_button(","                            label=\"最終成果物（ir.json + report.md）をZIPで保存\",","                            data=zip_bytes,","                            file_name=zip_name,","                            mime=\"application/zip\",","                            use_container_width=True,","                        )","","                        with st.expander(\"保存したIR（開発者向け）\"):","                            st.json(new_ir)","","                        # チャット履歴にも残す（画面の流れのため）","                        st.session_state[\"evi_messages\"].append(","                            {\"role\": \"assistant\", \"content\": \"IR（explanation追記済み）を新規保存しました。\", \"ts\": ts}","                        )","","                        st.stop()","","                # 通常：質問を表示・保存","                st.markdown(q_text)","                st.session_state[\"evi_messages\"].append(","                    {\"role\": \"assistant\", \"content\": q_text, \"ts\": ts}","                )","else:","    pass",""]}]]},"ace":{"folds":[],"scrolltop":0,"scrollleft":0,"selection":{"start":{"row":0,"column":0},"end":{"row":410,"column":0},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":0},"timestamp":1768965621069,"hash":"8d138a8e95b7f0618a3472e9a398d656e32d097a"}